package ru.memearena.meme.api; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import ru.memearena.meme.application.MemeService; import ru.memearena.ranking.api.*; import ru.memearena.ranking.application.RankingService; import ru.memearena.security.CurrentUser; import java.util.UUID;
@RestController @RequestMapping("/api/v1/memes") public class MemeController { private final MemeService memes; private final RankingService ranking; public MemeController(MemeService memes,RankingService ranking){this.memes=memes;this.ranking=ranking;} @PostMapping @Operation(summary="Create meme") public ResponseEntity<MemeResponse> create(@Valid @RequestBody CreateMemeRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(MemeResponse.from(memes.create(CurrentUser.required().userId(),r.title(),r.mediaAssetId(),r.imageUrl(),r.sourceUrl())));} @GetMapping("/{memeId}") @Operation(summary="Get meme") public MemeResponse get(@PathVariable UUID memeId){return MemeResponse.from(memes.get(memeId));} @GetMapping("/top") @Operation(summary="Get top memes") public TopMemesResponse top(@RequestParam(defaultValue="ALL_TIME") RankingPeriod period,@RequestParam(defaultValue="20") @Min(1) @Max(100) int limit){return ranking.top(period,limit);} }
